<template>
    <div class="layout">
      <Layout>
        <Header>
          <Menu mode="horizontal" theme="dark" active-name="1">
            <!--<div class="layout-logo"></div>-->
            <div class="layout-account">
              <!--<Avatar icon="ios-person" size="large" />-->
              <Submenu name="0">
                <template slot="title">{{account}}</template>
                <MenuItem name="0-1"><Button @click="loginout">退出</Button></MenuItem>
              </Submenu>
            </div>
            <div class="layout-nav">
              <router-link to="echars1"><MenuItem name="1"><Icon type="ios-navigate"></Icon>首页</MenuItem></router-link>
              <router-link to="book"><MenuItem name="2"><Icon type="ios-keypad"></Icon>图书管理</MenuItem></router-link>
              <router-link to="user"><MenuItem name="3"><Icon type="ios-analytics"></Icon>人员管理</MenuItem></router-link>
              <router-link to="contentme"><MenuItem name="4"><Icon type="ios-paper"></Icon>联系我们</MenuItem></router-link>
            </div>
          </Menu>
        </Header>
        <Layout :style="{padding: '0 50px'}">
          <Breadcrumb :style="{margin: '16px 0'}">
            <BreadcrumbItem>主页</BreadcrumbItem>
            <BreadcrumbItem>频道</BreadcrumbItem>
            <BreadcrumbItem>类别</BreadcrumbItem>
          </Breadcrumb>
          <Content :style="{padding: '24px 0', minHeight: '280px', background: '#fff'}">
            <Layout>
              <Sider hide-trigger :style="{background: '#fff'}">
                <Menu active-name="1-2" theme="light" width="auto" :open-names="['1']">
                  <Submenu name="1">
                    <template slot="title">
                      <Icon type="ios-navigate"></Icon>
                      男生频道
                    </template>
                    <MenuItem name="1-1">玄幻修真</MenuItem>
                    <MenuItem name="1-2">恐怖小说</MenuItem>
                    <MenuItem name="1-3">武侠小说</MenuItem>
                  </Submenu>
                  <Submenu name="2">
                    <template slot="title">
                      <Icon type="ios-keypad"></Icon>
                      女生频道
                    </template>
                    <MenuItem name="2-1">言情小说</MenuItem>
                    <MenuItem name="2-2">校园小说</MenuItem>
                  </Submenu>
                  <Submenu name="3">
                    <template slot="title">
                      <Icon type="ios-analytics"></Icon>
                      体育频道
                    </template>
                    <MenuItem name="3-1">体育杂志</MenuItem>
                    <MenuItem name="3-2">健身杂志</MenuItem>
                  </Submenu>
                </Menu>
              </Sider>
              <Content :style="{padding: '24px', minHeight: '800px', background: '#fff'}">
                <router-view></router-view>
              </Content>
            </Layout>
          </Content>
        </Layout>
        <Footer class="layout-footer-center">Copyright &copy; 2018  - 1029648408@qq.com</Footer>
      </Layout>
    </div>
</template>

<script>
    export default {
        name: "mainpage",
      data () {
        return {
          isCollapsed: false,
          account:"",               //用户名
        }
      },
      created(){
        //this.useraccount=this.$route.params.useraccount;      //旧方法路由传参方式获取账户信息
        this.account = window.localStorage.useraccount;         //把localstorge中账户名称取出
        this.echars1();
        // this.$router.push("/user")
        //  使用router.push 或者 router.replace 里面都不能让path和params同时存在  就是路由传参用name和params
      },
      methods: {
        echars1() {
          this.$router.push({
            name: 'echars1'
          });
          // this.getDeviceData();  //初始化数据
        },
        //注销登录
        loginout() {
          localStorage.removeItem('account');//清空用户
          //localStorage.clear('token');//清空token和其他数据
          localStorage.removeItem('token');//清空token信息
          //resolve();
          this.$router.push('/');
        },
      }
    }
</script>

<style scoped>
  .layout{
    border: 1px solid #d7dde4;
    background: #f5f7f9;
    position: relative;
    border-radius: 20px;  /*属性规定圆角边框属性*/
    overflow: hidden;     /*属性规定当内容溢出元素框时发生的事情*/
    padding-right: 10px;  /*属性规定盒子内边距右侧距离*/
    padding-left: 10px;   /*属性规定盒子内边距左侧距离*/
  }
  .layout-logo{
    width: 40px;
    height: 40px;
    /*background:#B0C4DE;*/
    background-image:url('../../assets/lamp1.jpg');
    background-position:center;
    background-size: cover;
    border-radius: 3px;
    float: right;
    position: relative;
    top: 10px;
    left: 20px;
  }
  .layout-account{
    border-radius: 1px;
    text-align: center;
    float: right;
    position: relative;
  }
  .layout-nav{
    width: 480px;
    margin: 0 auto;
    float: left;
    /*text-align: center;*/
    position: relative;
    /*margin-left: 20px;*/
  }
  .layout-footer-center{
    text-align: center;
  }
</style>



